fn fibonacci(n: i64) -> i64 {
    let mut fa = 0;
    let mut fb = 1;
    let mut fi = 0;
    while fi < n {
        let mut temp = fb;
        fb = fa + fb;
        fa = temp;
        fi = fi + 1;
    }
    return fa;
}

fn sum_range(start_val: i64, end_val: i64) -> i64 {
    let mut total = 0;
    let mut idx = start_val;
    while idx < end_val {
        total = total + idx;
        idx = idx + 1;
    }
    return total;
}

